package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getIgnoreSurroundingSpaces(), "Default CSVFormat should not ignore surrounding spaces");

        CSVFormat modified = original.withIgnoreSurroundingSpaces(true);
        assertNotNull(modified, "Modified CSVFormat should not be null");
        assertTrue(modified.getIgnoreSurroundingSpaces(), "Modified CSVFormat should ignore surrounding spaces");

        // Calling again on modified should keep ignoreSurroundingSpaces = true
        CSVFormat modifiedAgain = modified.withIgnoreSurroundingSpaces(true);
        assertTrue(modifiedAgain.getIgnoreSurroundingSpaces(), "Calling withIgnoreSurroundingSpaces again should keep ignoreSurroundingSpaces true");

        // The original instance should remain unchanged (immutability)
        assertFalse(original.getIgnoreSurroundingSpaces(), "Original CSVFormat should remain unchanged");
    }
}
